+#[pymethods]
+impl PyCacheStats {
+    /// `hits / (hits + misses)`, or `None` if no checked searches yet.
+    /// The headline cache-first KPI from ADR-155 §M1.5 (target ≥ 0.95).
+    fn hit_rate(&self) -> Option<f64> {
+        let total = self.hits + self.misses;
+        if total == 0 {
